		if c := a.TS.Compare(b.TS); c != 0 {
			return c
		}
		if c := cmp.Compare(a.URL, b.URL); c != 0 {
			return c
		}
		return cmp.Compare(string(a.Op), string(b.Op))
	})
	return out
}

