// newline.
func marshalPendingEntry(e PendingEntry) ([]byte, error) {
	if e.TSRaw == "" && !e.TS.IsZero() {
		e.TSRaw = e.TS.UTC().Format(time.RFC3339)
	}
	b, err := json.Marshal(e)
	if err != nil {
		return nil, fmt.Errorf("trust: marshal pending: %w", err)
	}
	return append(b, '\n'), nil
}

