	_, err := fmt.Fprintln(cmd.OutOrStdout(), line)
	return err
}

func stdinOrEmpty(cmd *cobra.Command) io.Reader {
	if in := cmd.InOrStdin(); in != nil {
		return in
	}
	return os.Stdin
}

