// firstShaFromLsRemote extracts the SHA from `git ls-remote` output.
// Lines that do not begin with a 40-char SHA are skipped to tolerate
// warnings printed to stdout on some git builds.
//
// Annotated-tag handling: `git ls-remote` reports an annotated tag on
// two lines — first the tag *object* SHA (which is not a commit), then
// the dereferenced commit SHA suffixed with `^{}`. Downstream
// [Repository.ReadTree] resolves SHAs through `CommitObject`, which
// fails for tag-object SHAs, so when a peeled (`^{}`) line is present
// we prefer it. For lightweight tags, branches, and SHA queries (single
// line, no peel) we fall back to the first matched SHA.
func firstShaFromLsRemote(stdout []byte) string {
	var firstSHA string
	for _, line := range strings.Split(string(stdout), "\n") {
		line = strings.TrimSpace(line)
		if len(line) < 40 {
			continue
		}
		candidate := strings.ToLower(line[:40])
		if !shaPattern.MatchString(candidate) {
			continue
		}
		if strings.HasSuffix(line, "^{}") {
			return candidate
		}
		if firstSHA == "" {
			firstSHA = candidate
		}
	}
	return firstSHA
}

// networkFailurePatterns is a small allowlist of substrings that strongly
// indicate a transport-level failure. The list is intentionally narrow:
// we prefer to mis-classify a rare network failure as ErrShellFailed than
// mask a credential or policy failure behind ErrRemoteUnreachable.
var networkFailurePatterns = []string{
	"Could not resolve host",
	"could not resolve host",
	"Temporary failure in name resolution",
	"Connection refused",
	"connection refused",
	"Network is unreachable",
	"network is unreachable",
	"No route to host",
	"no route to host",
	"Operation timed out",
	"Connection timed out",
	"connection timed out",
	"SSL_ERROR",
	"unable to access",
}

func looksLikeNetworkFailure(stderr []byte) bool {
	s := string(stderr)
	for _, pat := range networkFailurePatterns {
		if strings.Contains(s, pat) {
			return true
		}
	}
	return false
}

// Clone performs a bare clone of `url` into `dst`, which must be an
// empty or non-existent directory. The clone is bare (no working tree)
// because agent-sync reads repository contents through [ReadTree] /
// [BlobContent] rather than via a checkout.
//
// Parent directories of dst are created with 0o750 if missing; dst
// itself must not already exist as a populated directory (git refuses to
// clone into a non-empty target).
func Clone(ctx context.Context, rawURL, dst string) error {
	if err := checkInlineCredential(rawURL); err != nil {
		return err
	}
	if !filepath.IsAbs(dst) {
		return fmt.Errorf("git: clone: destination must be absolute, got %q", dst)
	}
	if err := os.MkdirAll(filepath.Dir(dst), 0o750); err != nil {
		return fmt.Errorf("git: clone: mkdir parent of %q: %w", dst, err)
	}

	// Tags are fetched on the initial clone (default git behavior — no
	// `--no-tags`) so a tag-pinned manifest can be materialized on a
	// fresh cache. This matches [Fetch], which uses `--tags` to keep
	// the mirror's tag namespace current on subsequent syncs.
	cmd, err := gitCmd(ctx, "", "clone", "--bare", "--quiet", "--", rawURL, dst)
	if err != nil {
		return err
	}
	_, stderr, err := runCapture(cmd, "clone")
	if err != nil {
		if looksLikeNetworkFailure(stderr) {
			return fmt.Errorf("%w: %w", ErrRemoteUnreachable, err)
		}
		return err
	}
	return nil
}

// Fetch updates the bare clone at `repoPath` from its origin remote.
// It fetches all branches and tags so a subsequent [Reachable] check has
// the data it needs.
func Fetch(ctx context.Context, repoPath string) error {
	if !filepath.IsAbs(repoPath) {
		return fmt.Errorf("git: fetch: repo path must be absolute, got %q", repoPath)
	}
	cmd, err := gitCmd(ctx, repoPath,
		"fetch", "--quiet", "--prune", "--tags",
		"origin",
		"+refs/heads/*:refs/heads/*",
	)
	if err != nil {
		return err
	}
	_, stderr, err := runCapture(cmd, "fetch")
	if err != nil {
		if looksLikeNetworkFailure(stderr) {
			return fmt.Errorf("%w: %w", ErrRemoteUnreachable, err)
		}
		return err
	}
	return nil
}

// IsAncestor returns true when `ancestor` is an ancestor of `descendant`
// in the repository at repoPath. Both arguments are resolved as refs or
// SHAs. This is the reachability check used to defend against
// force-pushed refs: after fetching, callers verify the pinned SHA is
// reachable from the configured ref.
//
// Pass fully-qualified refs (`refs/heads/<name>`, `refs/tags/<name>`) for
// `descendant` whenever a ref name could be ambiguous. `git merge-base
// --is-ancestor` resolves bare names through git's DWIM rules, which
// silently prefer tags over branches in some cases — leaving the
// reachability check evaluating the wrong ref. Use [HasRef] to probe for
// the qualified form before calling this function.
//
// A clean "false" answer is returned on exit code 1; any other exit is
// wrapped as [ErrShellFailed].
func IsAncestor(ctx context.Context, repoPath, ancestor, descendant string) (bool, error) {
	if !filepath.IsAbs(repoPath) {
		return false, fmt.Errorf("git: is-ancestor: repo path must be absolute, got %q", repoPath)
	}
	cmd, err := gitCmd(ctx, repoPath, "merge-base", "--is-ancestor", ancestor, descendant)
	if err != nil {
		return false, err
	}
	var stderr bytes.Buffer
	cmd.Stderr = &stderr
	err = cmd.Run()
	if err == nil {
		return true, nil
	}
	var exitErr *exec.ExitError
	if errors.As(err, &exitErr) {
		switch exitErr.ExitCode() {
		case 1:
			return false, nil
		}
	}
	return false, fmt.Errorf("%w: is-ancestor %s..%s: %w: %s", ErrShellFailed, ancestor, descendant, err, strings.TrimSpace(stderr.String()))
}

// ChangeSummary returns a human-readable summary of the commits between
// oldSHA (exclusive) and newSHA (inclusive) in the repository at repoPath
// — the content context `agent-sync update` shows at its confirmation gate
// so a human is deciding against real changes, not two opaque hashes. The
// output is `git log --oneline` limited to maxLines commits, with a
// trailing "… and N more commit(s)" line when the range is longer. Both
// SHAs must already be present in the local mirror (the caller fetches
// first). No network access. A repo with an unreachable oldSHA (history
// rewritten) is a caller concern surfaced earlier by the fast-forward
// guard; here it simply yields a shell error.
func ChangeSummary(ctx context.Context, repoPath, oldSHA, newSHA string, maxLines int) (string, error) {
	if !filepath.IsAbs(repoPath) {
		return "", fmt.Errorf("git: change-summary: repo path must be absolute, got %q", repoPath)
	}
	if maxLines <= 0 {
		maxLines = 20
	}
	rangeSpec := oldSHA + ".." + newSHA
	cmd, err := gitCmd(ctx, repoPath, "log", "--oneline", "--no-decorate", "--no-color",
		fmt.Sprintf("-n%d", maxLines), rangeSpec)
	if err != nil {
		return "", err
	}
	stdout, _, err := runCapture(cmd, "log "+rangeSpec)
	if err != nil {
		return "", err
	}
	summary := strings.TrimRight(string(stdout), "\n")

	countCmd, err := gitCmd(ctx, repoPath, "rev-list", "--count", rangeSpec)
	if err != nil {
		return "", err
	}
	countOut, _, err := runCapture(countCmd, "rev-list --count "+rangeSpec)
	if err != nil {
		return "", err
	}
	total, err := strconv.Atoi(strings.TrimSpace(string(countOut)))
	if err != nil {
		// nilerr: intentional. The commit list already succeeded; the total
		// count is only used to append a "… and N more" line. A malformed
		// count should degrade to the (complete, correct) commit list rather
		// than fail the whole update, so we return the summary we have.
		return summary, nil //nolint:nilerr
	}
	if total > maxLines {
		summary += fmt.Sprintf("\n… and %d more commit(s)", total-maxLines)
	}
	return summary, nil
}

// ResolveLocalRef resolves ref (a branch, tag, "HEAD", or SHA) to its
// 40-char commit SHA inside the local repository at repoPath. No network
// access — this is the local-path analogue of [LsRemote]/[ResolveRef].
// An empty ref defaults to HEAD. The peel pattern `<ref>^{commit}` ensures
// annotated tags resolve to the underlying commit.
func ResolveLocalRef(ctx context.Context, repoPath, ref string) (string, error) {
	if !filepath.IsAbs(repoPath) {
		return "", fmt.Errorf("git: resolve-local: repo path must be absolute, got %q", repoPath)
	}
	ref = strings.TrimSpace(ref)
	if ref == "" {
		ref = "HEAD"
	}
	cmd, err := gitCmd(ctx, repoPath, "rev-parse", "--verify", "--quiet", ref+"^{commit}")
	if err != nil {
		return "", err
	}
	stdout, _, err := runCapture(cmd, "rev-parse "+ref)
	if err != nil {
		return "", err
	}
	sha := strings.TrimSpace(string(stdout))
	if !shaPattern.MatchString(strings.ToLower(sha)) {
		return "", fmt.Errorf("git: resolve-local: %q did not resolve to a commit SHA (got %q)", ref, sha)
	}
	return sha, nil
}

// HasRef reports whether `ref` resolves to an object in the repository
// at repoPath. The check uses `git rev-parse --verify --quiet <ref>`,
// which exits 0 when the ref exists and 1 when it does not. Any other
// exit is wrapped as [ErrShellFailed].
//
// Pass fully-qualified refs (`refs/heads/<name>`, `refs/tags/<name>`,
// etc.) — the whole point of this helper is to disambiguate names that
// would otherwise be subject to git's DWIM resolution. Bare names "work"
// here too but defeat the purpose.
func HasRef(ctx context.Context, repoPath, ref string) (bool, error) {
	if !filepath.IsAbs(repoPath) {
		return false, fmt.Errorf("git: has-ref: repo path must be absolute, got %q", repoPath)
	}
	if strings.TrimSpace(ref) == "" {
		return false, fmt.Errorf("git: has-ref: empty ref")
	}
	cmd, err := gitCmd(ctx, repoPath, "rev-parse", "--verify", "--quiet", ref)
	if err != nil {
		return false, err
	}
	var stderr bytes.Buffer
	cmd.Stderr = &stderr
	err = cmd.Run()
	if err == nil {
		return true, nil
	}
	var exitErr *exec.ExitError
	if errors.As(err, &exitErr) {
		switch exitErr.ExitCode() {
		case 1:
			return false, nil
		}
	}
	return false, fmt.Errorf("%w: rev-parse --verify %q: %w: %s", ErrShellFailed, ref, err, strings.TrimSpace(stderr.String()))
}

